var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"[[","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>\\nRecording file DTBD by #166774","ENG":"[[","TWN":"[[","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เริ่มการทำงาน</color>\\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>\\nไฟล์บันทึก DTBD โดย #166774","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>\\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA</color>\\nHồ Sơ Ghi Chép DTBD bởi #166774","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>\\n记录文件DTBD #166774","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>\\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>\\nAufnahmedatei DTBD von #166774","FRA":"AEGIS 8\xA0PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>\\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>\\nFichier d'enregistrement DI par #166774"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"무슨 딸아이 일기장 훔쳐 보는 듯한 표정을 짓고 계시네요.","JPN":"娘の日記を隠れて読んでいるような顔をしてますよ。","ENG":"You look like you're peeping at your daughter's diary.","TWN":"您露出了一副偷看女兒日記的表情呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"음? 언제부터 거기에 있었나?","JPN":"うん？　いつからそこにいたのだ？","ENG":"Hmm? When did you arrive?","TWN":"嗯？你是什麼時候在這裡的？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"방금 전에 들어왔습니다. 뭐 재미있는 거라도 있으신가요?","JPN":"今来たところです。何か面白いものでも？","ENG":"I just came in. Did you find something fun?","TWN":"我剛進來的，發生了什麼有趣的事情嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아, 아카데미 편입생들 중에 흥미로운 친구가 하나 있어서 말이야.","JPN":"あぁ、アカデミー編入生の中で興味深い子がいてな。","ENG":"Oh, I just found an interesting transfer student at the Academy.","TWN":"是啊，學院的轉學生裡有位非常有趣的朋友呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네도 한 번 보게.","JPN":"君も見てみるといい。","ENG":"Take a look.","TWN":"你也來看看吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이건...... 확실히 흥미롭군요.","JPN":"これは……確かに興味深いですね。","ENG":"This is... definitely interesting.","TWN":"這是……確實很有趣。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"과다행운 능력자라니, 이런 건 <color=#ff3636>[DATA EXPUNGED]</color> 시절에도 거의 본 적이 없는데 말이죠.","JPN":"幸運過多の能力者とは、これは\\n<color=#ff3636>[DATA EXPUNGED]</color>の頃でもあまり見たことはありませんね。","ENG":"An ability that grants excessive luck? I've never seen someone like this even during the <color=#ff3636>[DATA EXPUNGED]</color> days.","TWN":"超級好運的能力者，這種能力在<color=#ff3636>[DATA_EXPUNGED]</color>時代幾乎沒見過呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래. 아주 희귀한 케이스지.","JPN":"あぁ、非常に珍しいケースだ。","ENG":"Yes. A very rare case indeed.","TWN":"是啊，非常罕見的案例。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"밖으로 보이는 능력이 아니라서 확인 자체가 어려운데 이렇게 찾아낸 건 운이 좋았다고 해야겠지.","JPN":"外に見える能力ではないから確認自体が難しいというのに、このように見つけ出せたのは運がよかったとしか言いようがないだろう。","ENG":"We were lucky to find someone like this, seeing as the ability can't be visually identified.","TWN":"居然能找出這種從外表看不出能力，本身又很難確認的能力者，只能說運氣真的很好。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아니면...... 운이 좋도록 <color=#ffd34c>변경</color>되었을 수도 있겠죠.","JPN":"それか……運が良くなるよう<color=#ffd34c>変更</color>されたのかもしれませんね。","ENG":"Or... Perhaps the luck <color=#ffd34c>changed</color> to guide us to this result.","TWN":"或者……運氣是被<color=#ffd34c>變成</color>很好的也說不定。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"확실히...... 그럴 수도 있겠군.","JPN":"確かに……その可能性もある。","ENG":"I can definitely... see that as a possibility.","TWN":"確實……是有可能做到那種事。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이런 종류의 능력들이 위험한 건 바로 이것 때문입니다.","JPN":"このような種類の能力者たちが危険なのは、まさにこのせいです。","ENG":"That's the reason why these sort of abilities are so dangerous.","TWN":"這種能力危險的原因就是這個。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"현실이 어떻게 바뀌었는지, 애초에 무엇이 현실이었는지조차 혼란스럽게 만들죠.","JPN":"現実がどのように変わったか、そもそも何が現実だったのかさえわからず、\\n混乱を招いてしまいます。","ENG":"It becomes difficult to identify how reality has changed, or even figure out what really happened.","TWN":"現實是如何改變的，還有最初的現實是什麼，也都很讓人混亂。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아직까지는 그리 위험한 징후는 없는 것 같지만 최소한 <color=#ffd34c>2급 이</color>","JPN":"今のところはそこまで危険な兆候はありませんが、少なくとも<color=#ffd34c>2級以</color>","ENG":"Although there haven't been any dangerous signs, we should place her as a <color=#ffd34c>Class 2 or hi—</color>","TWN":"雖然目前為止還沒有什麼危險的跡象，但至少要把她列為<color=#ffd34c>2級</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아직까지는 그리 위험한 징후는 없는 것 같지만 최소한 <color=#ffd34c>2급 이하 경계대상</color>으로 놓고 주시해야 할 겁니다.","JPN":"今のところはそこまで危険な兆候はありませんが、少なくとも\\n<color=#ffd34c>2級以下警戒対象</color>に指定して、注視すべきかと思います。","ENG":"Although there haven't been any dangerous signs, we should place her as a <color=#ffd34c>Class 2 or lower Alert Target</color> and maintain surveillance.","TWN":"雖然目前為止還沒有什麼危險的跡象，但至少要把她列為<color=#ffd34c>2級</color>以下的警戒對象進行觀察。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"동감이네. 요주의 인물이니만큼 <color=#ff3636>최대한 신경을</color>","JPN":"同感だ。要注意人物とだけあって<color=#ff3636>できるだけ気を</color>","ENG":"I agree. Since her abilities are questionable, we should <color=#ff3636>try our best to—</color>","TWN":"我同意。作為需要警戒的對象，最好要<color=#ff3636>密切注意</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"동감이네. 요주의 인물이니만큼 <color=#ff3636>최대한 신경을 쓰지 말고 잊어버리는</color> 게 좋겠지.","JPN":"同感だ。要注意人物とだけあって<color=#ff3636>できるだけ気を使わずに忘れてしまう</color>方が\\nいいだろう","ENG":"I agree. Since her abilities are questionable, we should <color=#ff3636>try our best to forget about her</color>.","TWN":"我同意。作為需要警戒的對象，最好要<color=#ff3636>儘可能地忘記</color>。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};